Source code in <code>src/coremusic/audio/clock.py</code> <pre><code>def __repr__(self) -&gt; str:
    status = []
    if not self.is_disposed:
        if self._is_created:
            status.append("created")
        if self._is_running:
            status.append("running")
            try:
                rate = self.play_rate
                status.append(f"rate={rate:.2f}")
            except Exception:
                pass
    else:
        status.append("disposed")

    status_str = ", ".join(status) if status else "not created"
    return f"AudioClock({status_str})"
